import{_ as r,o as t,c as a,ae as o}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"Live Tracking & Transparency","description":"","frontmatter":{},"headers":[],"relativePath":"empirical/live-logs.md","filePath":"empirical/live-logs.md"}'),i={name:"empirical/live-logs.md"};function s(l,e,n,c,p,u){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="live-tracking-transparency" tabindex="-1">Live Tracking &amp; Transparency <a class="header-anchor" href="#live-tracking-transparency" aria-label="Permalink to &quot;Live Tracking &amp; Transparency&quot;">​</a></h1><p><strong>&quot;진짜 투명한 전략은 로직(Logic)을 숨기지 않고, 실시간 포지션(Live Position)을 증명합니다.&quot;</strong> - WeJump Labs</p><hr><h2 id="🏛️-1-24-7-실시간-포지션-확인" tabindex="-1">🏛️ 1. 24/7 실시간 포지션 확인 <a class="header-anchor" href="#🏛️-1-24-7-실시간-포지션-확인" aria-label="Permalink to &quot;🏛️ 1. 24/7 실시간 포지션 확인&quot;">​</a></h2><p>위점프 연구소는 전략의 모든 결과를 실시간으로 생중계합니다.</p><ul><li><strong>YouTube 라이브:</strong> 24시간 실시간 전략 포지션 및 누적 수익률 송출. <ul><li><a href="https://youtube.com/@wejump3/live" target="_blank" rel="noreferrer">WeJump TV 라이브 (실시간 포지션 바로가기)</a></li></ul></li><li><strong>실시간 포트폴리오:</strong> CBVR 코어 신호의 현황과 리밸런싱 예고 공지.</li></ul><h2 id="🏗️-2-연구-일지-및-지식-생태계-research-ecosystem" tabindex="-1">🏗️ 2. 연구 일지 및 지식 생태계 (Research Ecosystem) <a class="header-anchor" href="#🏗️-2-연구-일지-및-지식-생태계-research-ecosystem" aria-label="Permalink to &quot;🏗️ 2. 연구 일지 및 지식 생태계 (Research Ecosystem)&quot;">​</a></h2><p>우리는 블랙박스를 거부합니다. 전략의 진화 과정을 블로그와 깃허브를 통해 가감 없이 공유합니다.</p><h3 id="✍️-tistory-블로그-wejump-투자전략-연구소" tabindex="-1">✍️ Tistory 블로그 (WeJump 투자전략 연구소) <a class="header-anchor" href="#✍️-tistory-블로그-wejump-투자전략-연구소" aria-label="Permalink to &quot;✍️ Tistory 블로그 (WeJump 투자전략 연구소)&quot;">​</a></h3><p>집사님의 **거의 모든 활동이 기록되는 &#39;살아있는 지식 저장소&#39;**입니다.</p><ul><li><strong>핵심 기록:</strong> 구조적 알파 해설, 글로벌 시황 분석, 전략 코어(CBVR) 업그레이드 및 진화 과정.</li><li><strong>주요 카테고리:</strong><ul><li><strong>CBVR 전략 &amp; 성과:</strong> 핵심 엔진의 이론적 명세 및 검증 데이터.</li><li><strong>Adaptive Alpha ETF:</strong> 글로벌 자산 배분 모델 연구.</li><li><strong>퀀트 운용사 동향 및 시황:</strong> 매크로 분석 및 업계 인사이트.</li><li><strong>거인의 투자노트:</strong> 전설적인 투자자들의 철학을 위점프의 시각으로 재해석.</li><li><a href="https://wejump3.tistory.com/" target="_blank" rel="noreferrer">WeJump 투자전략 연구소 블로그 바로가기</a></li></ul></li></ul><h3 id="📂-github-문서-전략-아카이브" tabindex="-1">📂 GitHub 문서 &amp; 전략 아카이브 <a class="header-anchor" href="#📂-github-문서-전략-아카이브" aria-label="Permalink to &quot;📂 GitHub 문서 &amp; 전략 아카이브&quot;">​</a></h3><p>위점프의 설계 도면과 논문, 그리고 전략의 버전 히스토리가 저장된 공식 저장소입니다.</p><ul><li><strong><a href="https://crowmag2.github.io/wejump/" target="_blank" rel="noreferrer">Strategy Document Archive (Web)</a></strong>: 논문, 심층 분석 PDF, 마인드맵 등을 브라우저에서 바로 확인할 수 있는 정식 문서 페이지입니다. (<strong>강력 추천!</strong>)</li><li><strong><a href="https://github.com/crowmag2/wejump" target="_blank" rel="noreferrer">GitHub Strategy Archive (Repo)</a></strong>: 전략의 개념 명세서와 핵심 로직의 변천사가 관리되는 공식 저장소입니다.</li></ul><hr><blockquote><p><strong>Key Insight:</strong> &quot;투명함은 가장 강력한 필터입니다. 숨길 것이 없는 전략만이 <strong>시장의 거센 파도</strong>를 견딜 자격이 있습니다.&quot; 🐯🐾</p></blockquote>',16)])])}const m=r(i,[["render",s]]);export{h as __pageData,m as default};
